import{_ as t,o,c as e,a0 as r}from"./chunks/framework.Bogozrur.js";const s=JSON.parse('{"title":"荆州早报 | 5月31日：暴雨之后，城市重启","description":"","frontmatter":{"title":"2026-05-31T00:00:00.000Z","date":"2026-05-31T00:00:00.000Z","categories":["chaojian"],"tags":["朝鉴","趋势洞察","新闻","经济"],"author":"银枢局"},"headers":[],"relativePath":"posts/chaojian/chaojian-2026-05-31.md","filePath":"posts/chaojian/chaojian-2026-05-31.md"}'),h={name:"posts/chaojian/chaojian-2026-05-31.md"};function i(l,a,u,n,q,c){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="荆州早报-5月31日-暴雨之后-城市重启" tabindex="-1">荆州早报 | 5月31日：暴雨之后，城市重启 <a class="header-anchor" href="#荆州早报-5月31日-暴雨之后-城市重启" aria-label="Permalink to &quot;荆州早报 | 5月31日：暴雨之后，城市重启&quot;">​</a></h1><blockquote><p>☀️ 早安荆州！今天是2026年5月31日，星期日，农历五月初五。白天多云转晴，最高气温30℃，最低气温21℃，南风微风。出门带把伞备着，高温要来了。</p></blockquote><hr><h2 id="📰-今日十条" tabindex="-1">📰 今日十条 <a class="header-anchor" href="#📰-今日十条" aria-label="Permalink to &quot;📰 今日十条&quot;">​</a></h2><h3 id="_1-荆州遭遇73年极值暴雨-城区曾-五停" tabindex="-1">1. 荆州遭遇73年极值暴雨，城区曾&quot;五停&quot; <a class="header-anchor" href="#_1-荆州遭遇73年极值暴雨-城区曾-五停" aria-label="Permalink to &quot;1. 荆州遭遇73年极值暴雨，城区曾&quot;五停&quot;&quot;">​</a></h3><p>5月18日以来，荆州遭遇历史极值强降雨，国家站24小时降水量达268.7毫米、1小时降水量71.7毫米，双双突破1953年建站以来纪录。中心城区一度全面实行停工、停产、停业、停运、停课&quot;五停&quot;措施。</p><h3 id="_2-1200名消防员驰援清淤-灾区逐步恢复" tabindex="-1">2. 1200名消防员驰援清淤，灾区逐步恢复 <a class="header-anchor" href="#_2-1200名消防员驰援清淤-灾区逐步恢复" aria-label="Permalink to &quot;2. 1200名消防员驰援清淤，灾区逐步恢复&quot;">​</a></h3><p>湖北消防救援机动总队连续奋战10天后，5月28日起从&quot;抢险转移&quot;转段至&quot;排涝清淤&quot;。1200名消防指战员深入王家巷等重灾区，高压水枪冲洗道路，排涝车抽排积水，帮助受灾群众重返家园。</p><h3 id="_3-暴雨致车辆受损-官方数据出炉" tabindex="-1">3. 暴雨致车辆受损，官方数据出炉 <a class="header-anchor" href="#_3-暴雨致车辆受损-官方数据出炉" aria-label="Permalink to &quot;3. 暴雨致车辆受损，官方数据出炉&quot;">​</a></h3><p>本轮强降水造成荆州中心城区大量车辆因积水受损，官方数据已公布。受损车辆的维修与赔偿事宜正在持续推进中，车主可关注相关渠道了解详情。</p><h3 id="_4-市委书记汪元程部署端午文旅活动" tabindex="-1">4. 市委书记汪元程部署端午文旅活动 <a class="header-anchor" href="#_4-市委书记汪元程部署端午文旅活动" aria-label="Permalink to &quot;4. 市委书记汪元程部署端午文旅活动&quot;">​</a></h3><p>5月29日，市委书记汪元程主持召开会议，复盘&quot;五一&quot;文旅成绩，谋划端午假期活动。强调要擦亮&quot;荆州十二时辰&quot;品牌，推进&quot;楚超燃荆楚·端午颂荆州&quot;主题活动，解决停车难、如厕难等痛点。市长李迎伟出席。</p><h3 id="_5-荆州城区137个纳凉点全面开放" tabindex="-1">5. 荆州城区137个纳凉点全面开放 <a class="header-anchor" href="#_5-荆州城区137个纳凉点全面开放" aria-label="Permalink to &quot;5. 荆州城区137个纳凉点全面开放&quot;">​</a></h3><p>高温来袭，荆州城区137个纳凉点全面开放，为环卫工人、快递员等户外工作者撑起&quot;遮阳伞&quot;。同时，变电站主动排障保障供电，三万用户&quot;稳&quot;享清凉。</p><h3 id="_6-荆州又一大型还迁小区抽签分房" tabindex="-1">6. 荆州又一大型还迁小区抽签分房 <a class="header-anchor" href="#_6-荆州又一大型还迁小区抽签分房" aria-label="Permalink to &quot;6. 荆州又一大型还迁小区抽签分房&quot;">​</a></h3><p>继荆州区和顺幸福里小区摇号分房后，位于荆州高新区的农高家园三期近日启动抽签分房工作，安置房分配持续推进。</p><h3 id="_7-京东生鲜-重走荔枝路-抵达荆州" tabindex="-1">7. 京东生鲜&quot;重走荔枝路&quot;抵达荆州 <a class="header-anchor" href="#_7-京东生鲜-重走荔枝路-抵达荆州" aria-label="Permalink to &quot;7. 京东生鲜&quot;重走荔枝路&quot;抵达荆州&quot;">​</a></h3><p>5月28日，京东生鲜&quot;重走荔枝路&quot;车队抵达第四站荆州。唐代荔枝北上长安在此卸船装车、完成水运转陆运的接力，千年贡道如今上演&quot;争鲜战&quot;。</p><h3 id="_8-荆州青年讲述奋斗故事-不躺平、敢作为" tabindex="-1">8. 荆州青年讲述奋斗故事：不躺平、敢作为 <a class="header-anchor" href="#_8-荆州青年讲述奋斗故事-不躺平、敢作为" aria-label="Permalink to &quot;8. 荆州青年讲述奋斗故事：不躺平、敢作为&quot;">​</a></h3><p>5月29日，&quot;荆彩新征程·奋斗者说&quot;第五场记者见面会在荆州大学城青年之家举行。来自医疗、工程、政务服务领域的三位青年代表，分享扎根一线的实干故事。</p><h3 id="_9-荆州多所公办幼儿园推进改扩建" tabindex="-1">9. 荆州多所公办幼儿园推进改扩建 <a class="header-anchor" href="#_9-荆州多所公办幼儿园推进改扩建" aria-label="Permalink to &quot;9. 荆州多所公办幼儿园推进改扩建&quot;">​</a></h3><p>荆州区第三幼儿园改扩建正在施工中。今年政府工作报告明确投入3891万元实施东方红中学改造、梅园幼儿园扩建等，新增学位390个。</p><h3 id="_10-气温逐日攀升-6月2日将迎34°c高温" tabindex="-1">10. 气温逐日攀升，6月2日将迎34℃高温 <a class="header-anchor" href="#_10-气温逐日攀升-6月2日将迎34°c高温" aria-label="Permalink to &quot;10. 气温逐日攀升，6月2日将迎34℃高温&quot;">​</a></h3><p>未来三天荆州气温持续走高：今天30℃，明天32℃，6月2日最高气温将达34℃并伴有小雨转中雨。高温叠加残余积水，防暑防潮两手都要抓。</p><hr><h2 id="💡-早报君说" tabindex="-1">💡 早报君说 <a class="header-anchor" href="#💡-早报君说" aria-label="Permalink to &quot;💡 早报君说&quot;">​</a></h2><p>暴雨刚走，高温就来了。荆州这座城市这个五月过得不容易——73年极值暴雨把城区泡了个遍，消防员连轴转10天才把水抽干，现在清淤还在继续。好消息是生活正在恢复正常：还迁房分了，纳凉点开了，端午文旅也在筹备了。今天30℃起步，6月2日直奔34℃，体感会更闷——别忘了，积水刚退的地方湿度大，出门多喝水，家里多通风。</p><hr><p><em>数据来源：荆州新闻网、腾讯网、今日头条、搜狐新闻、企鹅号等。如有侵权请联系删除。</em></p>',29)])])}const _=t(h,[["render",i]]);export{s as __pageData,_ as default};
